#!/usr/bin/env bash
# studio-lighting.sh — 影棚商业布光 (Studio Lighting) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="影棚商业布光 (Studio Lighting)"

usage() {
  cat <<EOF
studio-lighting.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./studio-lighting.sh             # interactive
  ./studio-lighting.sh --dry-run
  ./studio-lighting.sh --json
  ./studio-lighting.sh --explain
  ./studio-lighting.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "影棚商业布光 (Studio Lighting)" 工作流。

一句话: 在可控环境里从零搭出主光/辅光/轮廓光，得到光比和光型都受控的成片光——商业人像/产品的硬功底。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**主光定位（key）**: 先只开主光，定方向/高度/距离决定光型与面部塑形，选修饰器（softbox 柔/beauty dish 硬）。跳过先定主光 → 多灯同时开根本看不出谁在塑形，光一团乱。(evidence: [T03-S004])"
  "**测光/确认主光**: 用测光表测主光在主体位的读数（或看试拍直方图）作为曝光基准。跳过 → 曝光全靠猜，多次试拍浪费时间，光比不可控。(evidence: [T03-S004])"
  "**辅光/光比（fill）**: 加补光填暗部，按想要的反差把补光设在主光下 1–2 档（2:1 柔/4:1 戏剧）。跳过 → 暗部死黑或反差失控，立体感全无或太硬。(evidence: [T03-S004])"
  "**轮廓光/背景光（rim/back）**: 加轮廓光把主体从背景剥离 + 背景光控背景影调。跳过 → 主体与背景糊成一片，无空间纵深。(evidence: [T04-S019])"
  "**修饰器选择**: softbox（柔/宽容瑕疵）/octabox（圆 catchlight，通用）/beauty dish（硬、雕纹理，美妆）/grid（控溢光）。选错 → 该柔的太硬（皮肤瑕疵全暴露）或该雕的太平。(evidence: [T02-S012, T02-S013])"
  "**试拍微调**: 拍一张看效果，按暗部太黑/catchlight 位置/溢光逐项调。跳过 → 把瑕疵带进整组拍摄。"
)
declare -a FAILURE_MODES=(
  "**一次开全部灯**: 多灯同时开看不出谁在塑形 → 先关全部，只开主光定形，再逐盏加。**CLI 自检**: 「你是先把主光单独调好，还是一上来就全开？」"
  "**买灯不买修饰器/裸灯硬光**: 裸灯打人脸瑕疵全暴露、无商业感 → 修饰器才决定光质，预算优先投 softbox/octabox。**CLI 自检**: 「你的光质是修饰器塑的，还是裸灯/反光伞凑合？」"
  "**主体粘背景**: 没有轮廓/背景光，主体与背景糊一起 → 加 rim light 或拉开主体与背景距离。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "studio-lighting-walkthrough"
fi
